import 'package:flutter/material.dart';\nimport 'admin_dashboard.dart';\nimport 'infrastructure_management.dart';\nimport 'map_monitoring.dart';\nimport 'analytics.dart';\n\nclass AlertsManagement extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: Text('Alerts Management'),\n        backgroundColor: Colors.red,\n      ),\n      endDrawer: _buildNavDrawer(context),\n      body: Column(\n        children: [\n          Container(\n            padding: EdgeInsets.all(16),\n            child: Row(\n              children: [\n                _buildAlertSummary('Critical', '3', Colors.red),\n                _buildAlertSummary('Warning', '7', Colors.orange),\n                _buildAlertSummary('Info', '12', Colors.blue),\n              ],\n            ),\n          ),\n          Expanded(\n            child: ListView(\n              children: [\n                _buildAlertCard('Central Bridge Overload', 'Critical', '2 min ago', Colors.red),\n                _buildAlertCard('Power Grid High Usage', 'Warning', '15 min ago', Colors.orange),\n                _buildAlertCard('Tunnel Maintenance Due', 'Info', '1 hour ago', Colors.blue),\n                _buildAlertCard('Highway Congestion', 'Warning', '2 hours ago', Colors.orange),\n              ],\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildAlertSummary(String type, String count, Color color) {\n    return Expanded(\n      child: Card(\n        child: Padding(\n          padding: EdgeInsets.all(16),\n          child: Column(\n            children: [\n              Text(count, style: TextStyle(fontSize: 24, fontWeight: FontWeight.bold, color: color)),\n              Text(type),\n            ],\n          ),\n        ),\n      ),\n    );\n  }\n\n  Widget _buildAlertCard(String title, String severity, String time, Color color) {\n    return Card(\n      margin: EdgeInsets.all(8),\n      child: ListTile(\n        leading: Icon(Icons.warning, color: color),\n        title: Text(title),\n        subtitle: Text(time),\n        trailing: Chip(\n          label: Text(severity, style: TextStyle(color: Colors.white)),\n          backgroundColor: color,\n        ),\n      ),\n    );\n  }\n\n  Widget _buildNavDrawer(BuildContext context) {\n    return Drawer(\n      child: ListView(\n        children: [\n          DrawerHeader(\n            decoration: BoxDecoration(color: Colors.red),\n            child: Text('Admin Menu', style: TextStyle(color: Colors.white, fontSize: 24)),\n          ),\n          ListTile(\n            leading: Icon(Icons.dashboard),\n            title: Text('Dashboard'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => AdminDashboard())),\n          ),\n          ListTile(\n            leading: Icon(Icons.build),\n            title: Text('Infrastructure'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => InfrastructureManagement())),\n          ),\n          ListTile(\n            leading: Icon(Icons.map),\n            title: Text('Map Monitoring'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => MapMonitoring())),\n          ),\n          ListTile(\n            leading: Icon(Icons.warning),\n            title: Text('Alerts'),\n            onTap: () => Navigator.pop(context),\n          ),\n          ListTile(\n            leading: Icon(Icons.analytics),\n            title: Text('Analytics'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => Analytics())),\n          ),\n        ],\n      ),\n    );\n  }\n}